clearglobal w scr_rect tgt tgt_rect pr0ax pr1ax;ecc_step=50; n_steps=4;               % geometry: step amd their number to a cue[tgt, tgt_rect]=MakeTarget(6);screens=screen('Screens')[w, scr_rect]=screen(1,'OpenWindow')MakeImage(280,210);bc=127;                                        % absolute level: backgroundfc=73; cc=128; tc=0.5                          % increments: fixation, cues, testsclut_bg=ones(204,1)*[bc bc bc];        % abs CLUT: blank screenclut_all=[0; fc; cc; round(1.27*(-100:100)'*tc)]*[1 1 1]+bc;   % incr CLUT: all items are presentedclut_0=ones(204,1)*[0 0 0]+bc;            % incr CLUT: none is presentclut_f=[0; fc; ones(202,1)*0]*[1 1 1]+bc;clut_c=[0; 0; cc; ones(201,1)*0]*[1 1 1]+bc;clut_t=[0; 0; cc; (-100:100)'*tc]*[1 1 1]+bc;screen(w,'SetClut', clut_all);pausescreen(w,'SetClut', clut_0);% To be fast !!!SCREEN(w,'Preference','SetClutQuickly');SCREEN(w,'Preference','SetClutWaitVBL');GetSecs;pos=[-120 120]; nPos=length(pos);soa=[0 1 2 3 4]; nSoa=length(soa);%Initialize the PSI tables% Init PSIta=zeros(nPos, nSoa);tb=zeros(nPos, nSoa);nCases=nPos*nSoa;amin = log10(5); amax = log10(50); na = 21;xmin = amin-.5; xmax = amax+.5; nx = na+10;bmin = 2; bmax = 4; nb = 2;a = (amin:(amax-amin)/(na-1):(amax+0.0001));x = (xmin:(xmax-xmin)/(nx-1):(xmax+0.0001));b = bmin*(bmax/bmin).^(((1:nb)-1)/(nb-1));miss = 0.04;	% miss levelgamma = .5;		% 2AFCpr1ax = [];for ib=1:nb  for ia=1:na    pr1ax = [pr1ax; dprime(a(ia),b(ib),x)];  end  ibendpr1ax = gamma + (1-miss)*(1-gamma)*pr1ax;pr0ax = 1 - pr1ax;pab=ones([na*nb, 1])/(na*nb); ntr=0;% Init PSI stops hereif input('Start a new experiment? (y/n): ','s') == 'y'	for i=(1:nCases)		fname=['pab' num2str(i)];		eval(['save ' fname ' ntr pab'])	%	fname	endendfor m=1:1000	[tmp orderSet]=sort(rand(1,nCases));	for n=1:nCases		fname=['pab' num2str(orderSet(n))];		eval(['load ' fname]);		while 1			% determine test contrast for orderSet(n)			inext=PsiTest(pab,nx);			tc=10^(x(inext)-2)			clut_t=[0; 0; cc; (-100:100)'*tc]*[1 1 1]+bc;			side=[sign(rand-.5), sign(rand-.5)];%			side=[1 1];			posInd=1+floor((n-1)/nSoa);			soaInd=n-(posInd-1)*nSoa;			delay=floor(rand*6);%			delay=0;			blank=ceil(rand+.5);			theMovie=MakeMovie(soa(soaInd),delay,clut_0,clut_f,clut_c,clut_t);			[tmp nCluts]=size(theMovie); nCluts=nCluts/3;			cuePos=side*240;			tgtPos=side*pos(posInd);			tgtPos(blank)=1000;			SysBeep;			MakeImage(cuePos(1),tgtPos(1));			SCREEN(w,'ClutMovie',theMovie,0,0,nCluts);			SCREEN(w,'WaitVBL',33);			screen(w,'SetClut', clut_0);			SysBeep;			MakeImage(cuePos(2),tgtPos(2));			SCREEN(w,'ClutMovie',theMovie,0,0,nCluts);			[side soaInd posInd delay blank]			s=abs(GetKey);			answer=0;			if (s ~= 28) & (s ~= 29)				'skipped trial'			else				break			end			screen(w,'SetClut', clut_0);		end %while		if (s == 28) & (blank == 2)			answer=1;		end		if (s == 29) & (blank == 1)			answer=1;		end		answer		[tmp1 tmp2 pab]=PsiEst(pab, inext, answer, a, b);		ntr=ntr+1;		eval(['save ' fname ' ntr pab']);		ta(posInd,soaInd)=10^(tmp1-2); tb(posInd,soaInd)=tmp2;	end %n	ntr	ta	tb		end %mbreak%delay=5;soa=6;fixationMovie=[kron(ones(1,5),clut_0), kron(ones(1,5),clut_f)];for n=1:10	screen(w,'SetClut', clut_f);%	theMovie=MakeMovie(delay,soa,clut_0,clut_f,clut_c,clut_t);	cueAndTestMovie=[kron(ones(1,soa),clut_c), clut_t, clut_c];	[tmp nCluts]=size(cueAndTestMovie); nCluts=nCluts/3;	cueAndTestMovie=[cueAndTestMovie,kron(ones(1,10-nCluts),clut_c)];	HideCursor;	t1=GetSecs;	SCREEN(w,'ClutMovie',fixationMovie,0,0,200);	t2=GetSecs;	(t2-t1)/.015	SCREEN(w,'WaitVBL',delay);	SCREEN(w,'ClutMovie',cueAndTestMovie,0,0,10);	ShowCursor;	pause	screen(w,'SetClut', clut_0);endnClutsframes=info(3)freq=info(3)/info(2)break